(function (global) {
  if (global.Chart) {
    return;
  }

  class Chart {
    constructor(canvas, config) {
      this.canvas = canvas;
      this.ctx = canvas.getContext("2d");
      this.config = config;
      this.draw();
    }

    destroy() {
      this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    }

    draw() {
      const parent = this.canvas.parentElement;
      const width = Math.max(320, parent ? parent.clientWidth : 800);
      const height = Math.max(300, parent ? parent.clientHeight : 320);
      const ratio = global.devicePixelRatio || 1;

      this.canvas.width = width * ratio;
      this.canvas.height = height * ratio;
      this.canvas.style.width = `${width}px`;
      this.canvas.style.height = `${height}px`;
      this.ctx.setTransform(ratio, 0, 0, ratio, 0, 0);

      const type = this.config.type;
      const labels = this.config.data.labels || [];
      const datasets = this.config.data.datasets || [];

      this.ctx.clearRect(0, 0, width, height);
      this.drawFrame(width, height);

      if (type === "line") {
        this.drawLines(labels, datasets, width, height);
      } else {
        this.drawBars(labels, datasets[0] || { data: [] }, width, height);
      }
    }

    drawFrame(width, height) {
      const left = 48;
      const top = 24;
      const right = 18;
      const bottom = 48;

      this.plot = {
        left,
        top,
        width: width - left - right,
        height: height - top - bottom,
        bottom: height - bottom,
      };

      this.ctx.strokeStyle = "#cbd5e1";
      this.ctx.lineWidth = 1;
      this.ctx.beginPath();
      this.ctx.moveTo(left, top);
      this.ctx.lineTo(left, this.plot.bottom);
      this.ctx.lineTo(left + this.plot.width, this.plot.bottom);
      this.ctx.stroke();
    }

    getRange(values) {
      const numeric = values.filter((value) => Number.isFinite(value));
      if (numeric.length === 0) {
        return { min: 0, max: 1 };
      }

      let min = Math.min(...numeric);
      let max = Math.max(...numeric);

      if (min === max) {
        min -= 1;
        max += 1;
      }

      return { min, max };
    }

    drawBars(labels, dataset, width, height) {
      const values = (dataset.data || []).map(Number);
      const { max } = this.getRange(values.concat(0));
      const barGap = 2;
      const barWidth = Math.max(2, this.plot.width / Math.max(values.length, 1) - barGap);

      this.ctx.fillStyle = dataset.backgroundColor || dataset.borderColor || "#2563eb";

      values.forEach((value, index) => {
        const x = this.plot.left + index * (barWidth + barGap);
        const h = max === 0 ? 0 : (value / max) * this.plot.height;
        const y = this.plot.bottom - h;
        this.ctx.fillRect(x, y, barWidth, h);
      });

      this.drawTitle(dataset.label || "Value");
      this.drawSparseLabels(labels, width, height);
    }

    drawLines(labels, datasets, width, height) {
      const colors = ["#2563eb", "#0f766e", "#c2410c", "#7c3aed", "#be123c"];
      const allValues = datasets.flatMap((dataset) => (dataset.data || []).map(Number));
      const { min, max } = this.getRange(allValues);

      datasets.forEach((dataset, datasetIndex) => {
        const values = (dataset.data || []).map(Number);
        if (values.length === 0) {
          return;
        }

        this.ctx.strokeStyle = dataset.borderColor || colors[datasetIndex % colors.length];
        this.ctx.lineWidth = 2;
        this.ctx.beginPath();

        values.forEach((value, index) => {
          const x = this.plot.left + (index / Math.max(values.length - 1, 1)) * this.plot.width;
          const y = this.plot.bottom - ((value - min) / (max - min)) * this.plot.height;

          if (index === 0) {
            this.ctx.moveTo(x, y);
          } else {
            this.ctx.lineTo(x, y);
          }
        });

        this.ctx.stroke();
      });

      this.drawTitle((datasets[0] && datasets[0].label) || "Value");
      this.drawSparseLabels(labels, width, height);
    }

    drawTitle(title) {
      this.ctx.fillStyle = "#1f2933";
      this.ctx.font = "13px Arial, Helvetica, sans-serif";
      this.ctx.fillText(title, this.plot.left, 16);
    }

    drawSparseLabels(labels, width, height) {
      if (!labels.length) {
        return;
      }

      const maxLabels = 8;
      const step = Math.max(1, Math.ceil(labels.length / maxLabels));

      this.ctx.fillStyle = "#536171";
      this.ctx.font = "11px Arial, Helvetica, sans-serif";

      labels.forEach((label, index) => {
        if (index % step !== 0) {
          return;
        }

        const x = this.plot.left + (index / Math.max(labels.length - 1, 1)) * this.plot.width;
        this.ctx.save();
        this.ctx.translate(x, height - 24);
        this.ctx.rotate(-Math.PI / 5);
        this.ctx.fillText(String(label), 0, 0);
        this.ctx.restore();
      });
    }
  }

  global.Chart = Chart;
})(window);
